const express = require('express');
const cors = require('cors');
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  ImageRun, Header, Footer, PageNumber, LevelFormat, UnderlineType,
  TabStopType, TabStopPosition
} = require('docx');

const app = express();
app.use(cors());
app.use(express.json({ limit: '10mb' }));

// ── COMORO BRAND COLOURS ──
const BLUE = "002060";
const DARK = "002060";
const GRAY = "595959";
const WHITE = "FFFFFF";
const BODY = "777777";
const TITLE_COLOR = "002F65";
const BULLET_COLOR = "E9068B";

// ── LOGO BASE64 ──
const LOGO_BASE64 = "";


// ── FOOTER IMAGE BASE64 ──
const FOOTER_BASE64 = "";

function sp() { return null; } // spacer removed
function line() { return new Paragraph({ spacing: { before: 120, after: 120 }, border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: BLUE } }, children: [new TextRun("")] }); }

function buildDoc(data) {
  const { full_name, contact, sections } = data;

  const logoBuffer = Buffer.from(LOGO_BASE64, 'base64');

  const children = [];

  // ── LOGO ──
  children.push(new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 0, after: 200 },
    children: [new ImageRun({ 
      data: logoBuffer, 
      transformation: { width: 179, height: 65 },
      type: "jpg"
    })]
  }));

  // ── CANDIDATE NAME ──
  children.push(new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 0, after: 60 },
    children: [new TextRun({ text: full_name || "", bold: true, size: 32, color: BLUE, font: "Montserrat" })]
  }));

  // ── CONTACT LINE ──
  if (contact) {
    const parts = [contact.location, contact.phone, contact.email, contact.linkedin].filter(Boolean);
    children.push(new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 200 },
      children: [new TextRun({ text: parts.join("  •  "), size: 20, color: GRAY, font: "Montserrat" })]
    }));
  }

  children.push(line());

  // ── SECTIONS ──
  for (const section of (sections || [])) {
    if (!section || !section.title) continue;
    // Skip references section
    if (/references?\s*(available)?\s*(on\s*request)?$/i.test(section.title.trim())) continue;

    // Section heading — skip if it looks like a "profile/summary" label (handled inline)
    const isSummarySection = /^(profile|summary|professional summary|about me)$/i.test(section.title.trim());
    if (!isSummarySection) {
      children.push(new Paragraph({
        spacing: { before: 200, after: 80 },
        children: [new TextRun({ text: section.title.toUpperCase(), bold: true, size: 20, color: TITLE_COLOR, font: "Montserrat" })]
      }));
    }

    if (section.type === "text" && section.content) {
      children.push(new Paragraph({
        spacing: { before: 0, after: 60 },
        children: [new TextRun({ text: section.content, size: 20, color: BODY, font: "Montserrat" })]
      }));
    }

    else if (section.type === "bullets" && Array.isArray(section.items)) {
      for (const item of section.items) {
        const raw = typeof item === "string" ? item : (item.heading || "");
        const clean = raw.replace(/^[\s>\-\*]+(\d+[\.\)])?\s*/, "").trim();
        // Bold text before em dash or colon (e.g. "Sport & fitness –" or "Responsibilities:")
        const dashIdx = clean.search(/\s[–—]\s/);
        const colonIdx = clean.indexOf(":");
        let runs;
        if (dashIdx > 0 && dashIdx < 50) {
          runs = [
            new TextRun({ text: clean.substring(0, dashIdx + 2), bold: true, size: 20, color: BODY, font: "Montserrat" }),
            new TextRun({ text: clean.substring(dashIdx + 2), bold: false, size: 20, color: BODY, font: "Montserrat" })
          ];
        } else if (colonIdx > 0 && colonIdx < 40) {
          runs = [
            new TextRun({ text: clean.substring(0, colonIdx + 1), bold: true, size: 20, color: BODY, font: "Montserrat" }),
            new TextRun({ text: clean.substring(colonIdx + 1), bold: false, size: 20, color: BODY, font: "Montserrat" })
          ];
        } else {
          runs = [new TextRun({ text: clean, size: 20, color: BODY, font: "Montserrat" })];
        }
        children.push(new Paragraph({
          numbering: { reference: "bullets", level: 0 },
          spacing: { before: 20, after: 20 },
          children: runs
        }));
      }
    }

    else if ((section.type === "experience" || section.type === "education") && Array.isArray(section.items)) {
      for (const item of section.items) {
        if (!item) continue;

        // Dates — bold, navy, on top
        if (item.dates) {
          children.push(new Paragraph({
            spacing: { before: 140, after: 0 },
            children: [new TextRun({ text: item.dates, bold: true, size: 20, color: TITLE_COLOR, font: "Montserrat" })]
          }));
        }

        // Company – Role on same line, not bold
        const companyRole = [item.subheading, item.heading].filter(Boolean).join(" – ");
        if (companyRole) {
          children.push(new Paragraph({
            spacing: { before: 0, after: 20 },
            children: [new TextRun({ text: companyRole, bold: false, size: 20, color: BODY, font: "Montserrat" })]
          }));
        }

        // Location
        if (item.location) {
          children.push(new Paragraph({
            spacing: { before: 0, after: 10 },
            children: [new TextRun({ text: item.location, size: 20, color: GRAY, font: "Montserrat" })]
          }));
        }

        // Description — plain paragraph
        if (item.description) {
          children.push(new Paragraph({
            spacing: { before: 10, after: 10 },
            children: [new TextRun({ text: item.description, size: 20, color: BODY, font: "Montserrat" })]
          }));
        }

        // Bullets — smart rendering with bold label before colon
        for (const bullet of (item.bullets || [])) {
          const clean = bullet.replace(/^[\s>\-\*]+(\d+[\.\)])?\s*/, "").trim();
          const colonIdx = clean.indexOf(":");
          let runs;
          if (colonIdx > 0 && colonIdx < 40) {
            // "Responsibilities: blah" — bold the label
            runs = [
              new TextRun({ text: clean.substring(0, colonIdx + 1), bold: true, size: 20, color: BODY, font: "Montserrat" }),
              new TextRun({ text: clean.substring(colonIdx + 1), bold: false, size: 20, color: BODY, font: "Montserrat" })
            ];
          } else {
            runs = [new TextRun({ text: clean, size: 20, color: BODY, font: "Montserrat" })];
          }
          children.push(new Paragraph({
            numbering: { reference: "bullets", level: 0 },
            spacing: { before: 20, after: 20 },
            children: runs
          }));
        }

        // Key achievements
        if (item.key_achievements && item.key_achievements.length > 0) {
          children.push(new Paragraph({
            spacing: { before: 30, after: 10 },
            children: [new TextRun({ text: "Key achievements:", bold: true, size: 20, color: BODY, font: "Montserrat" })]
          }));
          for (const ach of item.key_achievements) {
            const cleanAch = ach.replace(/^[\s>\-\*]+(\d+[\.\)])?\s*/, "").trim();
            children.push(new Paragraph({
              numbering: { reference: "bullets", level: 0 },
              spacing: { before: 20, after: 20 },
              children: [new TextRun({ text: cleanAch, size: 20, color: BODY, font: "Montserrat" })]
            }));
          }
        }
      }
    }

  }

  // ── FOOTER ──
  const footerLogoBuffer = Buffer.from(FOOTER_BASE64, 'base64');
  const footer = new Footer({
    children: [
      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { before: 60, after: 60 },
        children: [new ImageRun({ 
          data: footerLogoBuffer, 
          transformation: { width: 500, height: 59 },
          type: "jpg"
        })]
      })
    ]
  });

  const doc = new Document({
    numbering: {
      config: [{
        reference: "bullets",
        levels: [{
          level: 0,
          format: LevelFormat.BULLET,
          text: "•",
          alignment: AlignmentType.LEFT,
          style: {
            run: { color: "E9068B", font: "Montserrat" },
            paragraph: { indent: { left: 360, hanging: 360 } }
          }
        }]
      }]
    },
    styles: {
      default: { document: { run: { font: "Calibri", size: 20, color: DARK } } }
    },
    sections: [{
      properties: {
        page: { size: { width: 11906, height: 16838 }, margin: { top: 1000, bottom: 1000, left: 1200, right: 1200 } }
      },
      footers: { default: footer },
      children
    }]
  });

  return doc;
}

// ── ROUTE ──
app.post('/build-cv', async (req, res) => {
  try {
    const data = req.body;
    if (!data || !data.full_name) {
      return res.status(400).json({ error: 'Invalid JSON — full_name required' });
    }

    const doc = buildDoc(data);
    const buffer = await Packer.toBuffer(doc);

    const filename = `${(data.full_name || 'CV').replace(/\s+/g, '_')}_Comoro.docx`;

    res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
    res.send(buffer);

  } catch (err) {
    console.error(err);
    res.status(500).json({ error: err.message });
  }
});

app.get('/', (req, res) => res.send('Comoro CV Builder API is running'));

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
